#!/bin/bash
awk '($7 == "502" || $7 == "20000" || $7 == "20001") && ($3 ~ /^10\./ || $3 ~ /^172\.(1[6-9]|2[0-9]|3[0-1])\./ || $3 ~ /^192\.168\./) && ($5 ~ /^10\./ || $5 ~ /^172\.(1[6-9]|2[0-9]|3[0-1])\./ || $5 ~ /^192\.168\./) {print $1, $3, $4, $5, $6, $7, $12}' conn.log | sort | uniq -c | sort -rn | head -n 20